    @classmethod
    def InitFromBuf(cls, buf, pos):
        tmpRem = REM()
        tmpRem.Init(buf, pos)
        return cls.InitFromObj(tmpRem)

    @classmethod
    def InitFromPackedBuf(cls, buf, pos=0):
        n = flatbuffers.encode.Get(flatbuffers.packer.uoffset, buf, pos)
        return cls.InitFromBuf(buf, pos+n)

    @classmethod
    def InitFromObj(cls, tmpRem):
        x = REMT()
        x._UnPack(tmpRem)
        return x

    # REMT
    def _UnPack(self, REM):
        if REM is None:
            return
        self.MESSAGE_ID = REM.MESSAGE_ID()
        self.CREATION_DATE = REM.CREATION_DATE()
        self.ORIGINATOR = REM.ORIGINATOR()
        self.OBJECT_NAME = REM.OBJECT_NAME()
        self.OBJECT_ID = REM.OBJECT_ID()
        self.NORAD_CAT_ID = REM.NORAD_CAT_ID()
        self.TIME_SYSTEM = REM.TIME_SYSTEM()
        self.REF_FRAME = REM.REF_FRAME()
        self.START_TIME = REM.START_TIME()
        self.STOP_TIME = REM.STOP_TIME()
        self.STEP_SIZE = REM.STEP_SIZE()
        if REM.REENTRY_DATA() is not None:
            self.REENTRY_DATA = RDM.RDMT.InitFromObj(REM.REENTRY_DATA())
        if REM.TRAJECTORY_OEM() is not None:
            self.TRAJECTORY_OEM = OEM.OEMT.InitFromObj(REM.TRAJECTORY_OEM())
        if REM.TRAJECTORY_OCM() is not None:
            self.TRAJECTORY_OCM = OCM.OCMT.InitFromObj(REM.TRAJECTORY_OCM())
        if REM.ATMOSPHERE() is not None:
            self.ATMOSPHERE = ATM.ATMT.InitFromObj(REM.ATMOSPHERE())
        if REM.HYPERSONIC_CONDITIONS() is not None:
            self.HYPERSONIC_CONDITIONS = HFC.HFCT.InitFromObj(REM.HYPERSONIC_CONDITIONS())
        self.PROPAGATOR_NAME = REM.PROPAGATOR_NAME()
        self.PROPAGATOR_VERSION = REM.PROPAGATOR_VERSION()
        self.AEROTHERMAL_MODEL = REM.AEROTHERMAL_MODEL()
        self.BREAKUP_MODEL = REM.BREAKUP_MODEL()
        self.OUTCOME = REM.OUTCOME()
        self.BREAKUP_MODE = REM.BREAKUP_MODE()
        self.ENTRY_INTERFACE_EPOCH = REM.ENTRY_INTERFACE_EPOCH()
        self.ENTRY_INTERFACE_ALTITUDE_M = REM.ENTRY_INTERFACE_ALTITUDE_M()
